#include "./main.h"

__global__ void 
extract_kernel(long d_Ne,
				fp* d_I){											


	int bx = blockIdx.x;												
	int tx = threadIdx.x;													
	int ei = (bx*NUMBER_THREADS)+tx;										


	if(d_Ne > ei){															

		d_I[ei] = exp(d_I[ei]/255);												

	}

}

__global__ void 
prepare_kernel(	long d_Ne,
				fp* d_I,											
				fp* d_sums,										
				fp* d_sums2){


	int bx = blockIdx.x;												
	int tx = threadIdx.x;												
	int ei = (bx*NUMBER_THREADS)+tx;										


	if(d_Ne > ei){															

		d_sums[ei] = d_I[ei];
		d_sums2[ei] = d_I[ei]*d_I[ei];

	}

}

__global__ void 
reduce_kernel(	long d_Ne,													
				long d_no,													
				int d_mul,													
				fp* d_sums,										
				fp* d_sums2,
				int gridDim){


    int bx = blockIdx.x;												
	int tx = threadIdx.x;												
	int ei = (bx*NUMBER_THREADS)+tx;										

	int nf = NUMBER_THREADS-(gridDim*NUMBER_THREADS-d_no);				
	int df = 0;															


	__shared__ fp d_psum[NUMBER_THREADS];										
	__shared__ fp d_psum2[NUMBER_THREADS];


	int i;


	if(d_no > ei){															

		d_psum[tx] = d_sums[ei*d_mul];
		d_psum2[tx] = d_sums2[ei*d_mul];

	}



	__syncthreads(); 



	if(nf == NUMBER_THREADS){

		for(i=2; i<=NUMBER_THREADS; i=2*i){

			if(0 == (tx+1) % i){											
				d_psum[tx] = d_psum[tx] + d_psum[tx-i/2];
				d_psum2[tx] = d_psum2[tx] + d_psum2[tx-i/2];
			}

			__syncthreads();
		}

		if(tx==(NUMBER_THREADS-1)){											
			d_sums[bx*d_mul*NUMBER_THREADS] = d_psum[tx];
			d_sums2[bx*d_mul*NUMBER_THREADS] = d_psum2[tx];
		}
	}

	else{ 

		if(bx != (gridDim - 1)){											

			for(i=2; i<=NUMBER_THREADS; i=2*i){								

				if(0 == (tx+1) % i){										
					d_psum[tx] = d_psum[tx] + d_psum[tx-i/2];
					d_psum2[tx] = d_psum2[tx] + d_psum2[tx-i/2];
				}

				__syncthreads();
			}

			if(tx==(NUMBER_THREADS-1)){										
				d_sums[bx*d_mul*NUMBER_THREADS] = d_psum[tx];
				d_sums2[bx*d_mul*NUMBER_THREADS] = d_psum2[tx];
			}
		}

		else{																

			for(i=2; i<=NUMBER_THREADS; i=2*i){								
				if(i <= nf){
					df = i;
				}
			}

			for(i=2; df >= i; i=2*i){											

				if(0 == (tx+1) % i && df > tx){								
					d_psum[tx] = d_psum[tx] + d_psum[tx-i/2];
					d_psum2[tx] = d_psum2[tx] + d_psum2[tx-i/2];
				}

				__syncthreads();
			}

			if((df-1) == tx){										

				for(i=(bx*NUMBER_THREADS)+df; i<(bx*NUMBER_THREADS)+nf; i++){						
					d_psum[tx] = d_psum[tx] + d_sums[i];
					d_psum2[tx] = d_psum2[tx] + d_sums2[i];
				}

				d_sums[bx*d_mul*NUMBER_THREADS] = d_psum[tx];
				d_sums2[bx*d_mul*NUMBER_THREADS] = d_psum2[tx];
			}
		}
	}

}

__global__ void 
srad_kernel(fp d_lambda, 
			int d_Nr, 
			int d_Nc, 
			long d_Ne, 
			int* d_iN, 
			int* d_iS, 
			int* d_jE, 
			int* d_jW, 
			fp* d_dN, 
			fp* d_dS, 
			fp* d_dW, 
			fp* d_dE, 
			fp d_q0sqr, 
			fp* d_c, 
			fp* d_I){


    int bx = blockIdx.x;												
	int tx = threadIdx.x;												
	int ei = bx*NUMBER_THREADS+tx;											
	int row;																
	int col;																


	fp d_Jc;
	fp d_dN_loc, d_dS_loc, d_dW_loc, d_dE_loc;
	fp d_c_loc;
	fp d_G2,d_L,d_num,d_den,d_qsqr;


	row = (ei+1) % d_Nr - 1;													
	col = (ei+1) / d_Nr + 1 - 1;												
	if(0 == (ei+1) % d_Nr){
		row = d_Nr - 1;
		col -= 1;
	}

	if(d_Ne > ei){															


		d_Jc = d_I[ei];														


		d_dN_loc = d_I[d_iN[row] + d_Nr*col] - d_Jc;						
		d_dS_loc = d_I[d_iS[row] + d_Nr*col] - d_Jc;						
		d_dW_loc = d_I[row + d_Nr*d_jW[col]] - d_Jc;						
		d_dE_loc = d_I[row + d_Nr*d_jE[col]] - d_Jc;						


		d_G2 = (d_dN_loc*d_dN_loc + d_dS_loc*d_dS_loc + d_dW_loc*d_dW_loc + d_dE_loc*d_dE_loc) / (d_Jc*d_Jc);	


		d_L = (d_dN_loc + d_dS_loc + d_dW_loc + d_dE_loc) / d_Jc;			


		d_num  = (0.5*d_G2) - ((1.0/16.0)*(d_L*d_L)) ;						
		d_den  = 1 + (0.25*d_L);												
		d_qsqr = d_num/(d_den*d_den);										


		d_den = (d_qsqr-d_q0sqr) / (d_q0sqr * (1+d_q0sqr)) ;				
		d_c_loc = 1.0 / (1.0+d_den) ;										


		if (d_c_loc < 0){													
			d_c_loc = 0;													
		}
		else if (d_c_loc > 1){												
			d_c_loc = 1;													
		}


		d_dN[ei] = d_dN_loc; 
		d_dS[ei] = d_dS_loc; 
		d_dW[ei] = d_dW_loc; 
		d_dE[ei] = d_dE_loc;
		d_c[ei] = d_c_loc;

	}

}

__global__ void 
srad2_kernel(	fp d_lambda, 
				int d_Nr, 
				int d_Nc, 
				long d_Ne, 
				int* d_iN, 
				int* d_iS, 
				int* d_jE, 
				int* d_jW,
				fp* d_dN, 
				fp* d_dS, 
				fp* d_dE, 
				fp* d_dW, 
				fp* d_c, 
				fp* d_I){


    int bx = blockIdx.x;												
	int tx = threadIdx.x;												
	int ei = bx*NUMBER_THREADS+tx;											
	int row;																
	int col;																


	fp d_cN,d_cS,d_cW,d_cE;
	fp d_D;


	row = (ei+1) % d_Nr - 1;												
	col = (ei+1) / d_Nr + 1 - 1;											
	if(0 == (ei+1) % d_Nr){
		row = d_Nr - 1;
		col -= 1;
	}

	if(d_Ne > ei){															


		d_cN = d_c[ei];														
		d_cS = d_c[d_iS[row] + d_Nr*col];										
		d_cW = d_c[ei];														
		d_cE = d_c[row + d_Nr * d_jE[col]];									


		d_D = d_cN*d_dN[ei] + d_cS*d_dS[ei] + d_cW*d_dW[ei] + d_cE*d_dE[ei];


		d_I[ei] = d_I[ei] + 0.25*d_lambda*d_D;								

	}

}

__global__ void 
compress_kernel(long d_Ne,
				fp* d_I){										


	int bx = blockIdx.x;												
	int tx = threadIdx.x;												
	int ei = (bx*NUMBER_THREADS)+tx;										


	if(d_Ne > ei){															

		d_I[ei] = log(d_I[ei])*255;												

	}

}

