#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <cuda_runtime.h>

#include "./main.h"
#include "./util/graphics/graphics.h"
#include "./util/graphics/resize.h"
#include "./util/timer/timer.h"

#include "./kernel_gpu_opencl_wrapper.h"

int platform_id_inuse = 0;            
int device_id_inuse = 0;              

void 
kernel_gpu_opencl_wrapper(	fp* image,											
							int Nr,												
							int Nc,												
							long Ne,											
							int niter,											
							fp lambda,											
							long NeROI,											
							int* iN,
							int* iS,
							int* jE,
							int* jW,
							int iter,											
							int mem_size_i,
							int mem_size_j)
{

#ifdef TIMING
    struct timeval tv;
    struct timeval tv_total_start, tv_total_end;
    struct timeval tv_init_end;
    struct timeval tv_h2d_start, tv_h2d_end;
    struct timeval tv_d2h_start, tv_d2h_end;
    struct timeval tv_kernel_start, tv_kernel_end;
    struct timeval tv_mem_alloc_start, tv_mem_alloc_end;
    struct timeval tv_close_start, tv_close_end;
    float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time = 0,
                d2h_time = 0, close_time = 0, total_time = 0;

    gettimeofday(&tv_total_start, NULL);
#endif

#ifdef TIMING
    gettimeofday(&tv_init_end, NULL);
    tvsub(&tv_init_end, &tv_total_start, &tv);
    init_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

	int blocks_x;

	int mem_size;															
	mem_size = sizeof(fp) * Ne;												

	fp* d_I;
	cudaMalloc(&d_I, mem_size);

	int* d_iN;
	cudaMalloc(&d_iN, mem_size_i);

	int* d_iS;
	cudaMalloc(&d_iS, mem_size_i);

	int* d_jE;
	cudaMalloc(&d_jE, mem_size_j);

	int* d_jW;
	cudaMalloc(&d_jW, mem_size_j);

	fp* d_dN;
	cudaMalloc(&d_dN, mem_size);

	fp* d_dS;
	cudaMalloc(&d_dS, mem_size);

	fp* d_dW;
	cudaMalloc(&d_dW, mem_size);

	fp* d_dE;
	cudaMalloc(&d_dE, mem_size);

	fp* d_c;
	cudaMalloc(&d_c, mem_size);

	fp* d_sums;
	cudaMalloc(&d_sums, mem_size);

	fp* d_sums2;
	cudaMalloc(&d_sums2, mem_size);

#ifdef  TIMING
  gettimeofday(&tv_mem_alloc_end, NULL);
  tvsub(&tv_mem_alloc_end, &tv_init_end, &tv);
  mem_alloc_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

	cudaMemcpy(d_I, image, mem_size, cudaMemcpyHostToDevice);
	cudaMemcpy(d_iN, iN, mem_size_i, cudaMemcpyHostToDevice);
	cudaMemcpy(d_iS, iS, mem_size_i, cudaMemcpyHostToDevice);
	cudaMemcpy(d_jE, jE, mem_size_j, cudaMemcpyHostToDevice);
	cudaMemcpy(d_jW, jW, mem_size_j, cudaMemcpyHostToDevice);

	size_t local_work_size = NUMBER_THREADS;

	int blocks_work_size;
	size_t global_work_size;
	blocks_x = Ne/(int)local_work_size;
	if (0 != Ne % (int)local_work_size){												
		blocks_x += 1;																	
	}
	blocks_work_size = blocks_x;
	global_work_size = blocks_work_size * local_work_size;						

	printf("max # of workgroups = %d, # of threads/workgroup = %d (ensure that device can handle)\n", (int)(global_work_size/local_work_size), (int)local_work_size);

	extract_kernel<<<blocks_work_size, local_work_size>>>(Ne, d_I);
	cudaDeviceSynchronize();

	prepare_kernel<<<blocks_work_size, local_work_size>>>(Ne, d_I, d_sums, d_sums2);
	cudaDeviceSynchronize();

	int blocks2_x;
	int blocks2_work_size;
	size_t global_work_size2;
	long no;
	int mul;
	int mem_size_single = sizeof(fp) * 1;
	fp total;
	fp total2;
	fp meanROI;
	fp meanROI2;
	fp varROI;
	fp q0sqr;

	blocks2_work_size = blocks_work_size;							
	global_work_size2 = global_work_size;
	no = Ne;														
	mul = 1;														

	while(0 != blocks2_work_size){

		reduce_kernel<<<blocks2_work_size, local_work_size>>>(Ne, no, mul, d_sums, d_sums2, blocks2_work_size);
		cudaDeviceSynchronize();

		no = blocks2_work_size;												
		if(1 == blocks2_work_size){
			blocks2_work_size = 0;
		}
		else{
			mul = mul * NUMBER_THREADS;										
			blocks_x = blocks2_work_size/(int)local_work_size;			
			if (0 != blocks2_work_size % (int)local_work_size){			
				blocks_x += 1;
			}
			blocks2_work_size = blocks_x;
			global_work_size2 = blocks2_work_size * (int)local_work_size;
		}

	}

	cudaMemcpy(&total, d_sums, mem_size_single, cudaMemcpyDeviceToHost);
	cudaMemcpy(&total2, d_sums2, mem_size_single, cudaMemcpyDeviceToHost);

	meanROI	= total / (fp)(NeROI);										
	meanROI2 = meanROI * meanROI;										
	varROI = (total2 / (fp)(NeROI)) - meanROI2;							
	q0sqr = varROI / meanROI2;											

	srad_kernel<<<blocks_work_size, local_work_size>>>(lambda, Nr, Nc, Ne, d_iN, d_iS, d_jE, d_jW, d_dN, d_dS, d_dW, d_dE, q0sqr, d_c, d_I);
	cudaDeviceSynchronize();

	srad2_kernel<<<blocks_work_size, local_work_size>>>(lambda, Nr, Nc, Ne, d_iN, d_iS, d_jE, d_jW, d_dN, d_dS, d_dE, d_dW, d_c, d_I);
	cudaDeviceSynchronize();

	for (iter=0; niter > iter; iter++){										

		fflush(NULL);

		prepare_kernel<<<blocks_work_size, local_work_size>>>(Ne, d_I, d_sums, d_sums2);
		cudaDeviceSynchronize();

		blocks2_work_size = blocks_work_size;							
		global_work_size2 = global_work_size;
		no = Ne;														
		mul = 1;														

		while(0 != blocks2_work_size){

			reduce_kernel<<<blocks2_work_size, local_work_size>>>(Ne, no, mul, d_sums, d_sums2, blocks2_work_size);
			cudaDeviceSynchronize();

			no = blocks2_work_size;												
			if(1 == blocks2_work_size){
				blocks2_work_size = 0;
			}
			else{
				mul = mul * NUMBER_THREADS;										
				blocks_x = blocks2_work_size/(int)local_work_size;			
				if (0 != blocks2_work_size % (int)local_work_size){			
					blocks_x += 1;
				}
				blocks2_work_size = blocks_x;
				global_work_size2 = blocks2_work_size * (int)local_work_size;
			}

		}

		cudaMemcpy(&total, d_sums, mem_size_single, cudaMemcpyDeviceToHost);
		cudaMemcpy(&total2, d_sums2, mem_size_single, cudaMemcpyDeviceToHost);

		meanROI	= total / (fp)(NeROI);										
		meanROI2 = meanROI * meanROI;										
		varROI = (total2 / (fp)(NeROI)) - meanROI2;							
		q0sqr = varROI / meanROI2;											

		srad_kernel<<<blocks_work_size, local_work_size>>>(lambda, Nr, Nc, Ne, d_iN, d_iS, d_jE, d_jW, d_dN, d_dS, d_dW, d_dE, q0sqr, d_c, d_I);
		cudaDeviceSynchronize();

		srad2_kernel<<<blocks_work_size, local_work_size>>>(lambda, Nr, Nc, Ne, d_iN, d_iS, d_jE, d_jW, d_dN, d_dS, d_dE, d_dW, d_c, d_I);
		cudaDeviceSynchronize();

	}

	printf("\n");

	compress_kernel<<<blocks_work_size, local_work_size>>>(Ne, d_I);
	cudaDeviceSynchronize();

	cudaMemcpy(image, d_I, mem_size, cudaMemcpyDeviceToHost);

#ifdef  TIMING
    gettimeofday(&tv_close_start, NULL);
#endif

	cudaFree(d_I);
	cudaFree(d_c);
	cudaFree(d_iN);
	cudaFree(d_iS);
	cudaFree(d_jE);
	cudaFree(d_jW);
	cudaFree(d_dN);
	cudaFree(d_dS);
	cudaFree(d_dE);
	cudaFree(d_dW);
	cudaFree(d_sums);
	cudaFree(d_sums2);

#ifdef  TIMING
	printf("Time spent in different stages of the application:\n");
    gettimeofday(&tv_close_end, NULL);
    tvsub(&tv_close_end, &tv_close_start, &tv);
    close_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
    tvsub(&tv_close_end, &tv_total_start, &tv);
    total_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;

    printf("Init: %f\n", init_time);
    printf("MemAlloc: %f\n", mem_alloc_time);
    printf("HtoD: %f\n", h2d_time);
    printf("Exec: %f\n", kernel_time);
    printf("DtoH: %f\n", d2h_time);
    printf("Close: %f\n", close_time);
    printf("Total: %f\n", total_time);
#endif
}

int 
main(	int argc, 
		char* argv []){
  printf("WG size of kernel = %d \n", NUMBER_THREADS);

	fp* image_ori;																
	int image_ori_rows;
	int image_ori_cols;
	long image_ori_elem;

	fp* image;															
	int Nr,Nc;													
	long Ne;

	int niter = 10;																
	fp lambda = 0.5;															

	int r1,r2,c1,c2;												
	long NeROI;														

	int* iN;
	int* iS;
	int* jE;
	int* jW;

	int iter;   
	long i;    
	long j;    

	int mem_size_i;
	int mem_size_j;

    int cur_arg;
	for (cur_arg = 1; argc > cur_arg; cur_arg++) {
        if (strcmp(argv[cur_arg], "-n") == 0) {
            if (cur_arg + 1 <= argc) {
		        niter = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        else if (strcmp(argv[cur_arg], "-l") == 0) {
            if (cur_arg + 1 <= argc) {
		        lambda = atof(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        else if (strcmp(argv[cur_arg], "-s") == 0) {
            if (cur_arg + 3 <= argc) {
                Nr = atoi(argv[cur_arg+1]);			
        		Nc = atoi(argv[cur_arg+2]);			
                cur_arg = cur_arg + (2);
            }
        }
        else if (strcmp(argv[cur_arg], "-p") == 0) {
            if (cur_arg + 1 <= argc) {
                platform_id_inuse = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        else if (strcmp(argv[cur_arg], "-d") == 0) {
            if (cur_arg + 1 <= argc) {
                device_id_inuse = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
    }

	image_ori_rows = 502;
